sql:
SELECT 
  (SELECT SUM(b.spent) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE STRFTIME('%Y', e.event_date) = '2020') -
  (SELECT SUM(b.spent) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE STRFTIME('%Y', e.event_date) = '2019') AS difference;

